package com.v2ray.ang.utilimport android.app.DownloadManagerimport android.content.BroadcastReceiverimport android.content.Contextimport android.content.Intentimport android.content.IntentFilterimport android.net.Uriimport android.os.Buildimport android.os.Environmentimport android.util.Logimport androidx.core.content.FileProviderimport com.v2ray.ang.BuildConfigimport kotlinx.coroutines.Dispatchersimport kotlinx.coroutines.withContextimport org.json.JSONObjectimport java.io.BufferedReaderimport java.io.Fileimport java.io.InputStreamReaderimport java.net.HttpURLConnectionimport java.net.URLdata class UpdateInfo(    val versionName: String,    val versionCode: Int,    val downloadUrl: String,    val updateType: String,     val releaseNotes: String)class UpdateChecker(private val context: Context) {    companion object {        private const val TAG = "UpdateChecker"        private const val VERSION_URL = "https:    }    suspend fun checkForUpdates(): UpdateInfo? {        return withContext(Dispatchers.IO) {            try {                val url = URL(VERSION_URL)                val connection = url.openConnection() as HttpURLConnection                connection.requestMethod = "GET"                connection.connectTimeout = 5000                connection.readTimeout = 10000                if (connection.responseCode == 200) {                    val reader = BufferedReader(InputStreamReader(connection.inputStream))                    val response = reader.readText()                    reader.close()                    connection.disconnect()                    val json = JSONObject(response)                    val latestVersionCode = json.getInt("versionCode")                    val currentVersionCode = BuildConfig.VERSION_CODE                    Log.d(TAG, "Current version: $currentVersionCode, Latest version: $latestVersionCode")                    if (latestVersionCode > currentVersionCode) {                        val minVersionCode = json.optInt("minVersionCode", 0)                        val updateType = if (currentVersionCode < minVersionCode) "force" else "optional"                        return@withContext UpdateInfo(                            versionName = json.getString("versionName"),                            versionCode = latestVersionCode,                            downloadUrl = json.getString("downloadUrl"),                            updateType = updateType,                            releaseNotes = json.optString("releaseNotes", "")                        )                    }                }            } catch (e: Exception) {                Log.e(TAG, "Check for updates failed", e)            }            return@withContext null        }    }    fun downloadAndInstallApk(updateInfo: UpdateInfo) {        try {            val request = DownloadManager.Request(Uri.parse(updateInfo.downloadUrl))                .setTitle("XieXieVPN 更新")                .setDescription("下载版本 ${updateInfo.versionName}")                .setNotificationVisibility(DownloadManager.Request.VISIBILITY_VISIBLE_NOTIFY_COMPLETED)                .setDestinationInExternalPublicDir(Environment.DIRECTORY_DOWNLOADS, "xiexievpn_update.apk")                .setAllowedNetworkTypes(DownloadManager.Request.NETWORK_WIFI or DownloadManager.Request.NETWORK_MOBILE)            val downloadManager = context.getSystemService(Context.DOWNLOAD_SERVICE) as DownloadManager            val downloadId = downloadManager.enqueue(request)            val receiver = object : BroadcastReceiver() {                override fun onReceive(context: Context, intent: Intent) {                    val id = intent.getLongExtra(DownloadManager.EXTRA_DOWNLOAD_ID, -1)                    if (id == downloadId) {                        installApk()                        context.unregisterReceiver(this)                    }                }            }            val intentFilter = IntentFilter(DownloadManager.ACTION_DOWNLOAD_COMPLETE)            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {                context.registerReceiver(receiver, intentFilter, Context.RECEIVER_NOT_EXPORTED)            } else {                context.registerReceiver(receiver, intentFilter)            }        } catch (e: Exception) {            Log.e(TAG, "Download failed", e)        }    }    private fun installApk() {        try {            val file = File(Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOWNLOADS), "xiexievpn_update.apk")            if (!file.exists()) {                Log.e(TAG, "APK file not found: ${file.absolutePath}")                return            }            val intent = Intent(Intent.ACTION_VIEW)            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {                val uri = FileProvider.getUriForFile(context, "${context.packageName}.provider", file)                intent.setDataAndType(uri, "application/vnd.android.package-archive")                intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_GRANT_READ_URI_PERMISSION            } else {                intent.setDataAndType(Uri.fromFile(file), "application/vnd.android.package-archive")                intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK            }            context.startActivity(intent)        } catch (e: Exception) {            Log.e(TAG, "Install APK failed", e)        }    }}